#include<bits/stdc++.h>
using namespace std;
int n,m,tot,tot1,in[200010],dp[200010];
bool del[200010];
int head[200010],nxt[200010];
struct Edge_lsqxx
{
    int to,r,p;
}e[200010];
struct Edge_qxx
{
    int u,v,r,p,id;
    bool operator<(const Edge_qxx&b)const
    {
        return r>b.r;
    }
}edge[200010];
void add(int u,int v,int r,int p)
{
    edge[++tot]={u,v,r,p,0};
    edge[tot].id=tot;
    e[++tot1]={v,r,p};
    nxt[tot1]=head[u];
    head[u]=tot1;
}
int main()
{
    scanf("%d%d",&n,&m);
    for(int i=1;i<=m;i++)
    {
        int a,b,r,p;
        scanf("%d%d%d%d",&a,&b,&r,&p);
        add(b,a,r,p);
        in[a]++;
    }
    sort(edge+1,edge+1+m);
    queue<int> q;
    for(int i=1;i<=n;i++)
    {
        if(in[i]==0)
        {
            q.push(i);
        }
    }
    memset(dp,0x3f,sizeof(dp));
    for(int i=1;i<=m;i++)
    {
        while(!q.empty())
        {
            int t=q.front();
            q.pop();
            for(int i=head[t];i;i=nxt[i])if(!del[i])
            {
                del[i]=true;
                int v=e[i].to,r=e[i].r,p=e[i].p;
                in[v]--;
                if(dp[t]<=1e9)
                {
                    dp[v]=min(dp[v],max(r,dp[t]-p));
                }
                if(in[v]==0)
                {
                    q.push(v);
                }
            }
        }
        if(del[edge[i].id])
        {
            continue;
        }
        del[edge[i].id]=true;
        int u=edge[i].u,v=edge[i].v,r=edge[i].r,p=edge[i].p;
        in[v]--;
        dp[v]=min(dp[v],r);
        if(in[v]==0)
        {
            q.push(v);
        }
    }
    for(int i=1;i<=n;i++)
    {
        if(dp[i]>1e9)
        {
            printf("-1 ");
        }
        else
        {
            printf("%d ",dp[i]);
        }
    }
    return 0;
}
